import os
import sys
from dataclasses import dataclass
from enum import Enum
from typing import Optional

class ArchiveType(Enum):
    ARCHIVE = "archive"

@dataclass
class ArchiveSpec:
    type: ArchiveType
    location: str
    permissions: Optional[str] = None

def archive_old_users(permissions: Optional[str] = None):
    archive_specs = [
        ArchiveSpec(ArchiveType.ARCHIVE, "/path/to/archive/january", "rwxr-xr-x"),
        {
            "type": ArchiveType.ARCHIVE,
            "location": "/path/to/archive/february",
            "permissions": "rwxrwxrwx"
        },
        # Add more archive specifications as needed
    ]

    for spec in archive_specs:
        if permissions:
            os.chmod(spec.location, spec.permissions)
            print(f"Archiving {spec.location} with permissions: {spec.permissions}")
        else:
            os.chmod(spec.location, "rwxrwxrwx")  # Default permissions

if __name__ == "__main__":
    if len(sys.argv) > 1:
        actions = sys.argv[1:]
        for action in actions:
            if action.lower() == "archive":
                archive_old_users(sys.argv[2])
            elif action.lower() == "verbose":
                print("\nVerbose mode *** Command: archive ***\n")
            else:
                print(f"Command not recognized: {action}")

    else:
        user_permissions = input("Enter user permissions: ")
        if user_permissions:
            archive_old_users(user_permissions)

