def make_forecast():
    location = request.form['location']
    api_key = '<PUT_YOUR_KEY_HERE>'

    # Replace 'YOUR_API_KEY_HERE' with your actual API key
    url = "http://api.openweathermap.org/data/2.5/weather"
    payload = {"APPID": api_key, "q": location, "units": "metric"}

    response = requests.get(url, params=payload)

    if response.status_code == 200:
        data = response.json()

        # Format the weather data into formattable and print
        formatted_data = {
            "Temperature": f"{data['main']['temp']}°C", 
            "Humidity": f"{data['main']['humidity']}%", 
            "Weather Description": data['weather'][0]['description']
        }
        print(f'You are at {formatted_data["Temperature"]} degrees in {formatted_data["Weather Description"]} with a humidity of {formatted_data["Humidity"]}%')
    else:
        print("Error: Unable to access the weather information. Check your API key and try again.")

